var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"골목에서도 쏟아져 나온다! 사격 개시!","JPN":"路地の方からもくるぞ！　射撃開始！","ENG":"They're pouring out from the alleys, too! Fire!","TWN":"巷子裡也有侵蝕體！開始射擊！"},"stage":{"bg":"PROLOGUE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"빌어먹을! 또 총알이 걸렸어!","JPN":"くそっ！　弾切れだ！","ENG":"Darn it! My gun's jammed again!","TWN":"該死！卡彈了！"},"stage":{"bg":"PROLOGUE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"여기도 한 명 당했다! 붕대 가져 와!","JPN":"こちら、一人負傷！　止血処置を！","ENG":"Man down! Medic!","TWN":"這裡有人受傷了！快拿紗布過來！"},"stage":{"bg":"PROLOGUE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"후우...... 도시 한복판에서 전쟁을 치르는군.","JPN":"ふう……都市のど真ん中で戦闘とは。","ENG":"Phew... They've turned downtown into a war zone.","TWN":"呼……沒想到會在市中心開戰。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"늘 있는 정화 작전이라더니, 하여튼 윗대가리 놈들.","JPN":"いつもの浄化作戦とか言いやがって、上のクソどもは。","ENG":"This was supposed to be a routine purification... I knew those top brass fools were up to no good.","TWN":"不是說就是個淨化作戰嗎？上頭這些人真是該死。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"강산아, 부상자들은?","JPN":"ヤマムラ君、負傷者は？","ENG":"Gangsan, what's the latest on casualties?","TWN":"江山，傷患呢？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L17_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"네, 팀장님! 지금 인근 구조대에 연락해서 병원으로 이송 중입니다!","JPN":"はい、班長！　今近くの救助隊に連絡して病院に移送中です！","ENG":"Sir! We managed to contact a nearby rescue squad to medevac the wounded!","TWN":"隊長！已經聯繫了附近的救助隊，正在送往醫院。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L18_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그래. 현장 잘 통제하고 민간인 절대 못 들어오게 잘 막아라.","JPN":"了解。民間人が絶対に立ち入らないように、現場の通行止めを頼むぞ。","ENG":"Good. Keep the site secure and don't let any civilians through.","TWN":"好，控制好現場，絕對不能讓老百姓進來。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"죄송합니다. 제가 조금만 더 잘 지켰더라도 부상자는 훨씬 적었을 텐데......","JPN":"申し訳ございません。僕がもう少しちゃんと対処していれば負傷者も少なかったはずなのに……","ENG":"I'm sorry, sir. If I did a better job of protecting them, we wouldn't have so many casualties...","TWN":"對不起，都是我的錯，否則也不會有這麼多人受傷……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그 사람들도 다 돈 받고 고용된 용병들이야. 자기가 다칠 줄 모르고 왔겠냐.","JPN":"そいつらは金で雇われた傭兵だ。怪我のリスクくらい、事前に承知しているだろ。","ENG":"Those mercs are all getting paid to do this. They knew what they were getting themselves into.","TWN":"那些人都是收錢做事的傭兵，他們應該都有了心理準備。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"아무도 너더러 책임지라고 한 적 없어. 지금 맡은 일에나 신경 써.","JPN":"誰も君に責任を負えなんて言わないから、今の仕事に集中しろ。","ENG":"Nobody expects you to take responsibility for them. Just focus on the task at hand.","TWN":"沒人讓你負責，你只要做好你自己的事就行了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"네! 시정하겠습니다!","JPN":"はい、是正します！","ENG":"Understood, sir!","TWN":"是！遵命！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"팀장님, 저기 보세요! 장갑차가 오고 있어요!","JPN":"班長、見てください！　装甲車が来ます！","ENG":"Sir, look! APC incoming!","TWN":"隊長，你看！有裝甲車正往這邊過來！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"장갑차......?","JPN":"装甲車……？","ENG":"APC?","TWN":"裝甲車……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"담당자인 박현수요. 그 많은 침식체들을 피해 오느라 고생이 이만저만 아니었겠수다.","JPN":"現場担当者のクボタ・ケンジです。あの侵食体の群れを避けてここまで来るとは、大変苦労されましたね。","ENG":"I'm Park Hyunsoo. I'm in charge here. You must have gone through hell dodging all those C.O.s out there.","TWN":"我是負責人朴賢秀，辛苦你們了，要避開那些侵蝕體不容易吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"오늘 겪은 불만 사항은 상담 센터로 전화하시오. 받을 직원이 있는지는 모르겠소만.","JPN":"今日の件について管理局に言いたいことがあれば相談センターに電話してください。今受付の人がいるかはわかりませんが。","ENG":"You can file any complaints about what happened today with the call center... Although I'm not sure anyone's there to pick up.","TWN":"今天有什麼不滿意的地方可以給客服中心打電話說一下，雖然不知道會不會有人接。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"소미야, 이 분들 상태는 어떠시냐?","JPN":"ミウラ君、この方たちの具合は？","ENG":"Somi, how are they holding up?","TWN":"小美，他們狀態如何？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"아, 네! 한 분만 부상이 심한 것 같아서 응급 치료 중이에요!","JPN":"あ、はい！　一人だけかなり傷が深くて、応急処置中です！","ENG":"I'm performing first aid on one of them. She's the only one who's been seriously wounded!","TWN":"只有一位看起來傷得很重，現在正在急救中！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"그런데 굉장하시네요. 이렇게 많이 다쳤는데 치료하는 동안 신음 한 번 안 내시고.","JPN":"でも本当にすごい方です。これだけ傷を負ったのに治療中にうめき声すら出さないなんて。","ENG":"I've got to say I'm impressed... You've been battered pretty badly but you haven't even let out a moan.","TWN":"不過，真是厲害。明明傷得這麼重，治療的時候都不哼一下。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"도착했을 때...... 제 부상이 그렇게나 심했나요?","JPN":"私の負傷は……そんなにひどかったのでしょうか？","ENG":"Were my wounds... that severe when I arrived?","TWN":"我來這裡的時候……傷得很嚴重嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"당연하죠. 저라면 아프다고 데굴데굴 구르다 팀장님한테 한소리 들었을 걸요?","JPN":"そうですよ！　私だったら痛くて痛くて泣き叫んで班長にいい加減にしろって怒られたはずです。","ENG":"Definitely. If it was me, I would've screamed in pain till my boss told me to shut up.","TWN":"對啊，如果換作是我，估計痛得到處打滾，最後還得被隊長訓一下。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......그랬군요.","JPN":"……そうでしたか。","ENG":"I see.","TWN":"……原來如此。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"헤헤, 근데 진짜 신기하네요. 저 메이드가 진짜 있는지 오늘 처음 알았어요.","JPN":"ヘヘッ、でも本当に珍しいですね。本物のメイドさんは初めて見ました。","ENG":"In any case, this is amazing. I never knew maids really existed.","TWN":"嘿嘿，不過真的好神奇，原來真的有女僕啊，我今天才知道呢。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"드러내고 활동할 입장이 아니기 때문이죠.","JPN":"表に出て活動するような立場にありませんので。","ENG":"Our activities have been fairly clandestine... for a reason.","TWN":"因為我們不能暴露身份。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"물밑에서 조용히 주인을 모시는 것. 그것이야말로 모범적인 메이드의 자세입니다.","JPN":"影から静かにご主人様に仕える存在。それこそ模範的なメイドの心構えでしょう。","ENG":"A true maid knows how to serve her master discreetly.","TWN":"在背後好好侍奉主人，那才是模範女僕該做的事。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"그래요? 새롭게 하나 배워 가네요!","JPN":"そうなんですか？　また一つ勉強になりました！","ENG":"Really? Well, I guess I learn something new!","TWN":"是嗎？原來如此！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네도 소미님한테 새 반창고를 받아가지 말임다! 감사함다!","JPN":"モネもヒマワリ様から新しい絆創膏をいただくっす！　ありがとっす！","ENG":"And I got a new bandage from you, Ms. Somi! Thank you!","TWN":"小美也給莫妮貼新的OK繃了！謝謝！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"응, 응. 새로 붙여 줬으니까 너무 심하게 뛰어놀면 안 돼?","JPN":"うん、いいよ。取り替えてあげる。はしゃぎ回ると取れちゃうから気を付けてね。","ENG":"Yeah, don't get too rowdy or it'll come off, okay?","TWN":"嗯嗯，貼了新的OK繃，可不能隨便亂跑囉！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"그리고 어디 보자, 사장님은......","JPN":"えーと、この社長さんには……","ENG":"And as for your boss...","TWN":"讓我看看，老闆你……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"반창고 대신 덕트 테이프라도 구해 드릴까요?","JPN":"絆創膏の代わりにダクトテープでも持ってきましょうか？","ENG":"Should I get you some duct tape instead?","TWN":"要不我幫你貼幾個強力膠布吧？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아니, 괜찮네. 나야 보다시피 흠집 하나 없이 아주 멀쩡해.","JPN":"いや、遠慮しておこう。見てのとおり元気だ。","ENG":"No thanks. As you can see, there's not a scratch on me.","TWN":"不用了，沒關係。妳也看到了，我沒傷到一分一毫。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러고 보니 내가 사장인지는 어떻게 알았나?","JPN":"そういえば私が社長ということはどうしてわかったのかね？","ENG":"How did you know I was the boss by the way?","TWN":"對了，妳怎麼知道我是老闆？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"모르셨어요? 인터넷에 있는 태스크포스 커뮤니티에서는 유명하시거든요.","JPN":"知らないんですか？　ネットのタスクフォースコミュニティでは有名ですよ？","ENG":"Oh, didn't you know? You're pretty famous on the online TASKFORCE forums.","TWN":"你不知道嗎？你在特遣勢力論壇可出名了。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"이제 곧 기계가 인류를 지배하는 시대가 올 거라면서요.","JPN":"まもなく機械が人類を支配する時代が来るってみんな騒いでますよ。","ENG":"They're saying the machines will reign over humanity soon.","TWN":"大家都說不久的未來會是由機器統治人類。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"무지막지한 오해를 받고 있구만......","JPN":"とんでもない誤解だな……","ENG":"Sounds like there's been a huge misunderstanding...","TWN":"看來大家都對我的誤會很深啊……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"아마 오늘 일이 알려지면 더 유명해지실 걸요?","JPN":"今日の出来事でもっと有名になりそうですね！","ENG":"I bet you'll be even more famous after today!","TWN":"今天的事傳了出去，就更出名了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"인간 메이드를 거느리는 로봇 주인님이라니!","JPN":"人間のメイドを従えるロボットのご主人様だなんて！","ENG":"A robot master with human maids!","TWN":"你可是帶領人類女僕的機器主人啊！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잠시 돕는 것뿐일세. 메이드가 있다는 게 그렇게 중요한 일인가?","JPN":"しばらく手伝ってもらっているだけだ。メイドがいるということはそんなに驚くことか？","ENG":"They're just giving me a hand for the time being. Is it such a big deal to have a maid?","TWN":"她只是暫時幫忙而已。況且，有沒有女僕有那麼重要嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"별 관계는 없지만 요새 메이드와 관련한 이야기가 많이 돌고 있거든요.","JPN":"特に関係はないですが、最近メイドに関する噂がたくさん出回っているんですよ。","ENG":"Well, it's probably unrelated, but there's been a lot of talk about maids lately.","TWN":"雖然沒什麼關係，但最近有很多關於女僕的傳言。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"메이드복을 입은 여자애들이 용병들을 찾아다니면서 질문을 던진다고 하던데요?","JPN":"メイド服を着た女の子たちが傭兵のところを訪ねて、聞き回っているらしいです。","ENG":"Apparently a couple of girls in maid outfits have been asking the mercenaries questions.","TWN":"聽說有穿著女僕裝的女孩子們到處找傭兵。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>메이드를 본 적 있나요?</color> 라고요.","JPN":"<color=#ffd34c>メイドを見たことありますか？</color>　って。","ENG":"They've been asking <color=#ffd34c>if anyone's seen another maid like them</color>.","TWN":"還問他們，<color=#ffd34c>有沒有看過女僕？</color>"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"봤다고 하면 피처럼 새빨간 소스가 뚝뚝 떨어지는 엄청 매운 샌드위치를 먹이고,","JPN":"見たと答えると血みたいに真っ赤なソースが滴る超辛口サンドイッチを食べさせて、","ENG":"If you answer \\"yes\\", they feed you extremely spicy sandwiches dripping with blood-red sauce.","TWN":"如果說看到了，就給他們吃醬汁紅的跟血一樣的辣三明治，"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"못 봤다고 하면 피처럼 새빨간 소스가 뚝뚝 떨어지는 무지 매운 샌드위치를 먹인대요.","JPN":"見なかったと応えると血みたいに真っ赤なソースが滴る激辛サンドイッチを食べさせるらしいです。","ENG":"If you answer \\"no\\", they feed you super spicy sandwiches dripping with blood-red sauce.","TWN":"如果說沒看到，就給他們吃醬汁紅的跟血一樣的超辣三明治。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"그 샌드위치를 한 입이라도 먹은 사람은 입에서 불을 뿜게 된다는 괴담이......!","JPN":"そのサンドイッチを口にした人は、口から火を噴き出すという噂が……！","ENG":"Rumors say just one bite of that sandwich will light your tongue on fire!","TWN":"而且傳言說只要吃了一口那個三明治，就會噴火呢……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"히익......! 무, 무섭지 말임다!","JPN":"ひい……！　こ、怖い話っすね！","ENG":"Eeek! Th-that's scary!","TWN":"嚇咿……！好、好可怕！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"그래서 들리는 소문으론 샌드위치의 피해자들이 두 사람을 잡으려고 벼른다나 봐요.","JPN":"それで、サンドイッチの被害者たちがその二人を捕まえようと目を光らせて探しているようです。","ENG":"Sounds like the victims of the sandwiches are hell-bent on catching those two.","TWN":"那些三明治受害者好像在找那兩個女僕。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"혹시 여기 두 분도 오해 받을까 봐...... 헤헷.","JPN":"だからここにいるお二人のことを誤解されないか心配で……ヘヘッ。","ENG":"I just figured you two might be suspected of being the culprits... Hah hah.","TWN":"所以，我這不是擔心這兩位會被誤會嘛……嘿嘿。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그거 참 희한한 소문이긴 하군. 총알을 먹인다면 모를까 매운 샌드위치라니.","JPN":"それは飛んだ噂話だな。弾丸を食らわすならまだしも、激辛サンドイッチだなんて。","ENG":"That sure sounds like a strange rumor. They feed you hot sandwiches instead of bullets?","TWN":"那真是奇怪的傳聞啊。給他們吃子彈還說的過去，怎麼會給他們辣三明治。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"죄송하지만, 혹시 제가 그 메이드 분들을 만날 수 있을까요?","JPN":"申し訳ございませんが、私がそのメイドの方々に会うことはできますでしょうか？","ENG":"Excuse me, but do you think I could meet those maids?","TWN":"那個，可以讓我見見那些女僕嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"네? 잘은 모르겠지만 아마......","JPN":"どうですかね？　よくわからないけど多分……","ENG":"Huh? I'm not sure, but...","TWN":"啊？雖然我不是很清楚……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"심소미, 너 사람들 붙잡고 또 수다 떠는 거냐? 근무 시간엔 근무를 해야지.","JPN":"ミウラ君、また市民の方とおしゃべりか？　勤務時間には仕事をしなさい。","ENG":"Somi, are you chatting on duty again? Get to work!","TWN":"沈小美，妳又在跟人家閒聊啊？上班時間應該好好工作。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"아, 네! 지금 바로 갈게요, 팀장님!","JPN":"あっ、はい！　今すぐ行きます、班長！","ENG":"Oh! Coming, boss!","TWN":"啊，好的！我現在就去，隊長！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"블랙 네트워크에 글을 올려 보세요! 계속 사람을 찾고 다닌다면 확인할 수도 있으니까요!","JPN":"ブラックネットワークに書き込んでみてください！　まだ探し回っているなら情報があると思いますよ！","ENG":"Try putting up a post on the Dark Network! You might come across them if they're still looking for the other maid!","TWN":"你在黑色網路上寫篇文章吧！說不定她們能看見！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"그럼 이만 가 볼게요! 베로니카 님은 꼭 병원 가 보시고요!","JPN":"では失礼しますね！　ベロニカさんは後で病院に行ってちゃんと治療を受けてくださいね！","ENG":"Well, I'd better get going! And be sure to see a doctor, Veronica!","TWN":"那我走了！貝洛妮卡，妳一定要去醫院看看哦！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"감사함다~!","JPN":"ありがとっす！","ENG":"Thank you, ma'am!","TWN":"謝謝~！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};